<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('doctor'); require_once __DIR__.'/../../backend/shared/layout.php';
$id=(int)($_GET['id']??0); $st=db()->prepare('SELECT v.*,p.hn,p.first_name,p.last_name FROM visits v JOIN patients p ON p.id=v.patient_id WHERE v.id=?');$st->execute([$id]);$v=$st->fetch(); if(!$v) exit('not found');
