app_header('รายละเอียด Visit','doctor','dashboard'); ?><a class="back" href="patient-profile.php?hn=<?=urlencode($v['hn'])?>">← กลับข้อมูลผู้ป่วย</a><div class="card"><div class="tl-head"><h3><?=e($v['visit_date'])?> · <?=e($v['hn'])?> <?=e($v['first_name'].' '.$v['last_name'])?></h3><span class="badge blue"><?=e($v['visit_type'])?></span></div><p><b>โรงพยาบาล:</b> <?=e($v['hospital_name'])?> · <b>แผนก/Ward:</b> <?=e($v['department'])?> / <?=e($v['ward'])?> · <b>แพทย์:</b> <?=e($v['doctor_name'])?></p><p><b>มาเพราะ:</b> <?=e($v['chief_complaint'])?></p><p><b>วินิจฉัย:</b> <?=e($v['diagnosis'])?></p><p><b>อาการเพิ่มเติม:</b> <?=e($v['symptom_note'])?></p><?php if($v['surgery_flag']):?><div class="notice"><b>ผ่าตัด:</b> <?=e($v['surgery_detail'])?> · <?=e($v['anesthesia_type'])?> <?=$v['major_surgery_flag']?'· ผ่าตัดใหญ่':''?></div><?php endif;?><div class="grid three" style="margin-top:16px"><div class="card"><b>BP</b><div class="num"><?=e($v['sbp'])?>/<?=e($v['dbp'])?></div></div><div class="card"><b>Pulse</b><div class="num"><?=e($v['pulse'])?></div></div><div class="card"><b>SpO2</b><div class="num"><?=e($v['spo2'])?>%</div></div></div></div><div class="grid two" style="margin-top:18px"><div class="card"><h3>ยา</h3><?php foreach($meds as $m):?><p>💊 <b><?=e($m['drug_name'])?></b> <?=e($m['dose'])?> <?=e($m['frequency'])?> <?=e($m['duration'])?></p><?php endforeach;?></div><div class="card"><h3>ยาฉีด/วัคซีน</h3><?php foreach($injs as $m):?><p>💉 <b><?=e($m['injection_name'])?></b> <?=e($m['dose'])?> <?=e($m['route'])?></p><?php endforeach;?><?php foreach($vacs as $m):?><p>🛡 <b><?=e($m['vaccine_name'])?></b> เข็ม <?=e($m['dose_no'])?> Lot <?=e($m['lot_no'])?></p><?php endforeach;?></div></div><?php if($d):?><div class="card" style="margin-top:18px"><h3>Diabetes Follow-up</h3><div class="grid four"><div>HbA1c <b><?=e($d['hba1c'])?></b></div><div>FPG <b><?=e($d['fpg'])?></b></div><div>eGFR <b><?=e($d['egfr'])?></b></div><div>UACR <b><?=e($d['uacr'])?></b></div></div></div><?php endif; ?><?php app_footer();?>
